arguments.command:
# Let me check what 汀桑 was doing on June 1 - check the messages in his session
python3 -c "
import json
with open('/root/.openclaw/agents/father/sessions/d220c090-37be-4b18-8134-ef12a8aa90a5.jsonl') as f:
    for line in f:
        try:
            obj = json.loads(line)
            if obj.get('type') == 'message':
                msg = obj.get('message', {})
                role = msg.get('role', '')
                content = msg.get('content', '')
                ts = obj.get('timestamp', '')
                # Only get user messages for timeline
                if role == 'user':
                    if isinstance(content, list):
                        text = ''.join([c.get('text','') for c in content if isinstance(c, dict) and c.get('type')=='text'])
                    else:
                        text = str(content)[:300]
                    print(f'{ts} | USER: {text[:200]}')
        except:
            pass
" 2>/dev/null | head -60

